import asyncio
import websockets
import json
from collections import defaultdict

class GameServer:
    def __init__(self):
        self.clients = {}
        self.inventories = defaultdict(list)
        self.lock = asyncio.Lock()

    async def register(self, websocket, player_id):
        self.clients[player_id] = websocket
        await websocket.send(json.dumps({"type": "welcome", "player_id": player_id}))

    async def unregister(self, player_id):
        if player_id in self.clients:
            del self.clients[player_id]

    async def handle_trade(self, data):
        async with self.lock:
            from_player = data['from']
            to_player = data['to']
            item = data['item']

            if item in self.inventories[from_player]:
                self.inventories[from_player].remove(item)
                self.inventories[to_player].append(item)
                await self.notify_trade_success(from_player, to_player, item)
            else:
                await self.notify_trade_failure(from_player, item)

    async def notify_trade_success(self, from_player, to_player, item):
        if from_player in self.clients:
            await self.clients[from_player].send(json.dumps({"type": "trade_success", "item": item, "to": to_player}))
        if to_player in self.clients:
            await self.clients[to_player].send(json.dumps({"type": "trade_success", "item": item, "from": from_player}))

    async def notify_trade_failure(self, from_player, item):
        if from_player in self.clients:
            await self.clients[from_player].send(json.dumps({"type": "trade_failure", "item": item}))

    async def handle_client(self, websocket, path):
        player_id = await websocket.recv()
        await self.register(websocket, player_id)

        try:
            async for message in websocket:
                data = json.loads(message)
                if data['type'] == 'trade':
                    await self.handle_trade(data)
        finally:
            await self.unregister(player_id)

    async def main(self):
        async with websockets.serve(self.handle_client, "localhost", 8765):
            await asyncio.Future()

if __name__ == "__main__":
    server = GameServer()
    asyncio.run(server.main())